window.__dh_data = window.__dh_data || {};
window.__dh_data["ca"] = {
  "": "Content-Type: text/plain; charset=UTF-8\nContent-Transfer-Encoding: 8bit\n",
  "title": "Dhammapada",
  "chaps": "Capítols",
  "fontsize": "Mida de la lletra",
  "chap1": "Versos Bessons",
  "1": "La ment precedeix les experiències; la ment les inicia i elabora. Aquell que parla o actua amb la ment ofuscada, el malestar l'encalça, com la roda el peu del bou.",
  "2": "La ment precedeix les experiències; la ment les inicia i elabora. Aquell que parla o actua amb la ment clara, el benestar l'encalça, inseparable com l'ombra.",
  "3": "'M'ha insultat!, m'ha ferit!, m'ha vençut!, m'ha robat!' Els que es queixen així, no apaivaguen l'odi.",
  "4": "'M'ha insultat!, m'ha ferit!, m'ha vençut!, m'ha robat!' Els que no es queixen així, apaivaguen l'odi.",
  "5": "Perquè no és mai amb l'odi que l'odi s'apaivaga, sinó amb l'absència d'odi. Aquesta llei és eterna.",
  "6": "Tot i que altres no ho comprenen, això és el que hem de practicar. Aquells que ho comprenen, aturen les batalles.",
  "7": "Aquell que es deixa emportar, no té domini dels sentits, consumeix sense mesura i és indolent i apàtic, Mara el destruirà. Com un arbre feble, la ventada el parteix.",
  "8": "Aquell que no es deixa emportar, té domini dels sentits, consumeix amb mesura i és confiat i energètic, Mara no el pot destruir. Com una muntanya de roca, resisteix la ventada.",
  "9": "Aquell que es cenyeix l'hàbit safrà però no ha superat els mals hàbits, no es mereix l'hàbit safrà, perquè li manca sinceritat.",
  "10": "Aquell que ha superat els mals hàbits i té una bona conducta, es mereix l'hàbit safrà, perquè té sinceritat.",
  "11": "Els que consideren essencial el que no ho és, i inessencial el que és essencial, no arriben a l'essència, perquè pensen erròniament.",
  "12": "Els que reconeixen l'essencial com a essencial i l'inessencial com a inessencial, arriben a l'essència, perquè pensen correctament.",
  "13": "Com la pluja s'infiltra en una casa mal coberta, així el desig s'infiltra en una ment desentrenada.",
  "14": "Com la pluja no s'infiltra en una casa ben coberta, així el desig no s'infiltra en una ment ben entrenada.",
  "15": "En el món s'entristeix, al més enllà s'entristeix, el que fa el mal s'entristeix aquí i allà. S'entristeix i es turmenta en veure la impuresa dels seus actes.",
  "16": "En el món s'alegra, al més enllà s'alegra, el que fa el bé s'alegra aquí i allà. S'alegra i està content en veure la puresa dels seus actes.",
  "17": "En el món pateix, al més enllà pateix, el que fa el mal pateix aquí i allà. Pateix perquè ha fet mal; més patirà quan vagi a un mal destí!",
  "18": "En el món gaudeix, al més enllà gaudeix, el que fa el bé gaudeix aquí i allà. Gaudeix perquè ha fet bé; més gaudirà quan vagi a un bon destí!",
  "19": "Encara que reciti molt les escriptures, qui està distret no les està complint. Com un pastor que compta les vaques d'algú altre, aquest no fa vida d'asceta.",
  "20": "Encara que reciti poc les escriptures, qui es comporta segons l'ensenyament, abandona l'engany odi i desig, es manté atent i té la ment lliure perquè no s'agafa a això ni a allò, aquest és digne de la vida d'asceta.",
  "chap2": "L'Atenció",
  "21": "L'atenció és el camí de l'immortal, la distracció és el camí de la mort. Els que estan atents no moren, però els distrets són com morts.",
  "22": "Els que han comprès aquesta diferència, els experts en l'atenció, gaudeixen estant atents, s'alegren de fer el camí dels purs.",
  "23": "Meditant perseverants i esforçant-se amb constància, els savis viuen en l'estat de pau, la seguretat més gran.",
  "24": "El renom creix de qui s'esforça i és conscient, actua amb puresa i amb prudència, viu l'ensenyament amb atenció i amb domini de si mateix.",
  "25": "Amb esforç i amb atenció, autodomini i entrenament, l'assenyat s'ha de fer una illa que no s'emporti l'aiguat.",
  "26": "Els necis, arrauxats, persegueixen distraccions; l'assenyat guarda l'atenció com el tresor més preuat.",
  "27": "Les distraccions no li calen, ni aficionar-se als plaers; meditant i estant atent, obté la joia més gran.",
  "28": "Quan el savi amb l'atenció desvia tota distracció, encimbellat al palau del coneixement, estable com una muntanya, contempla ell que no té neguit el patiment dels necis.",
  "29": "Atent entre els distrets, ben despert entre adormits, l'assenyat va al davant, com el cavall veloç avança el feble.",
  "30": "Maghavà, amb l'atenció va arribar a ser el senyor dels déus. L'atenció sempre és lloada; la distracció, reprovada.",
  "31": "El monjo que es lliura a l'atenció i veu el risc d'estar distret, va cremant els lligams, petits i grans, com si fos un foc encès.",
  "32": "El monjo que es lliura a l'atenció i veu el risc d'estar distret, incapaç de tornar enrere, ja es troba en l'estat de pau.",
  "chap3": "La Ment",
  "33": "La ment, vacil·lant i erràtica, és difícil de guardar i refrenar, però l'assenyat l'adreça, com la sageta el sageter.",
  "34": "Com un peix llençat a terra, que algú ha tret fora de l'aigua, aquesta ment cueja fins que no surt del regne de Mara.",
  "35": "És bo domar la ment, que és difícil de subjectar, va lleugera i es posa allà on li sembla; una ment ben domada aporta benestar.",
  "36": "L'assenyat vigila la ment, que és difícil de veure, és subtil i es posa allà on li sembla; una ment ben vigilada aporta benestar.",
  "37": "Els que refrenen la ment, que és esmunyedissa, solitària, incorpòria i secreta, s'alliberen del lligam de Mara.",
  "38": "Aquell que no té la ment quieta, ignora l'ensenyament veritable i li manca constància, no creix en coneixement.",
  "39": "Però si refrena la pensa, ha oblidat les ferides i ha deixat anar bé i mal, està despert i no té res a témer.",
  "40": "Considereu que aquest cos és un gerro que encercla la ciutat de la ment; combateu Mara amb l'arma del coneixement i vigileu la conquesta sense repòs.",
  "41": "Ai! Ben aviat aquest cos jaurà damunt la terra, deixalla inconscient, inútil com un tronc.",
  "42": "El mal que es fan els enemics o aquells que més s'odien, pot fer-lo molt més gran una ment mal entrenada.",
  "43": "Ni una mare, ni un pare, ni cap altre parent podria fer tant de bé com una ment ben entrenada.",
  "chap4": "Les Flors",
  "44": "Qui conquerirà aquesta terra i el món de Yama amb els seus déus? Qui collirà la doctrina veritable i ben ensenyada, com qui cull una flor?",
  "45": "El deixeble conquerirà la terra i el món de Yama amb els seus déus; el deixeble collirà la doctrina veritable i ben ensenyada, com qui cull una flor amb destresa.",
  "46": "Qui sap que aquest cos és com l'escuma i entén que és un miratge, talla les flors de Mara i camina invisible per al Rei de la Mort.",
  "47": "Car, si cull les flors l'home de ment distreta, la mort arriba i se l'emporta, com l'aiguat s'endú un poble adormit.",
  "48": "Car, si cull les flors l'home de ment distreta, mai satisfet de plaers, la Mort en fa el seu vassall.",
  "49": "Com l'abella xucla el pol·len de la flor sense tocar-ne el color ni l'olor, així mateix el monjo silenciós ha de caminar pels poblats.",
  "50": "Que no es fixi en les faltes dels altres, ni en el que fan o no fan; que es fixi en si mateix i en el que fa o no fa.",
  "51": "Com una flor que és bonica, però no té color ni aroma, és estèril dir veritats sense portar-les a la pràctica.",
  "52": "Com una flor que és bonica, acolorida, aromàtica, és profitós dir veritats portant-les a la pràctica.",
  "53": "Igual que d'una pila de flors se'n pot fer moltes garlandes, el mortal pot fer molt de bé amb aquesta vida.",
  "54": "L'aroma de la flor no va a contravent, sigui de sàndal, tàgara o llessamí; l'aroma dels virtuosos va a contravent, la virtut de l'home de bé bufa en totes direccions.",
  "55": "L'aroma de sàndal o tàgara, de lotus o llessamí, no es poden comparar amb l'aroma de la virtut.",
  "56": "De poc abast és l'aroma del sàndal o de la tàgara; l'aroma dels virtuosos arriba fins als déus.",
  "57": "Mara no barra el camí dels virtuosos que estan atents, dels que són lliures perquè comprenen amb justesa.",
  "58": "Igual que en un munt de deixalles llançades al carrer hi pot créixer una flor de lotus, olorosa, estimulant,",
  "59": "així, entre la gentalla encegada i vulgar, el deixeble del Ben Despert resplendeix pel coneixement.",
  "chap5": "Necis",
  "60": "Llarga és la nit per al desvetllat, llarg el camí per al fatigat, llarg el revoltar dels necis que no coneixen la doctrina veritable.",
  "61": "Si el caminant no troba algú igual o millor que ell mateix, val més que faci camí sol; el neci no fa companyia.",
  "62": "'Tinc fills, tinc riqueses!', això va pensant el neci; però si no es té a si mateix, per a què vol fills i riqueses?",
  "63": "El neci que se sap estúpid és savi precisament per això; del neci que es creu un savi, en veritat cal dir-ne 'estúpid'.",
  "64": "Per bé que tota la vida el neci segui amb el mestre, no tastarà la veritat; és com la cullera, que no coneix el gust de la sopa.",
  "65": "Però si l'assenyat s'asseu un sol moment amb el mestre, al punt tasta la veritat; és com la llengua, que coneix el gust de la sopa.",
  "66": "Els necis desassenyats! són enemics de si mateixos, perquè fan males accions que tenen un fruit amarg.",
  "67": "Una acció no és bona si causa penediment, si hom en rep el resultat amb llàgrimes i plors.",
  "68": "Però una acció és bona si no causa penediment, si hom en rep el resultat alegre i satisfet.",
  "69": "El neci s'ho passa bé mentre no madura el mal, però quan el mal madura, llavors troba els patiments.",
  "70": "Encara que el neci mengi amb un bri d'herba anys i anys, comprendre l'ensenyament val setze vegades més.",
  "71": "Una acció mal feta no es pot canviar ràpidament, com la llet es qualla; persegueix el neci cremant-lo com un foc ocult entre les cendres.",
  "72": "La fama li arriva al neci per al seu propi perjudici; destrueix la seva sort com una maledicció.",
  "73": "Desitja una consideració immerescuda, preeminència entre els monjos, autoritat als monestirs i que el venerin a les cases.",
  "74": "'Que vegin el que jo faig tant els monjos com els laics, que depenguin de mi en tot pel que cal o no cal fer.' Quan el neci pensa això, el desig i l'orgull creixen.",
  "75": "Però l'un és el camí del guany, l'altre, el que duu a l'estat de pau. Sabent això, el monjo el deixeble del Despert, que no celebri l'honor i aprengui a discriminar.",
  "chap6": "Savi",
  "76": "Si trobes qui exposa el que està ocult, veu els defectes i reprova assenyadament, has de seguir un savi com aquest; seguint-lo, aniràs bé, i no malament.",
  "77": "Qui aconsella, instrueix i priva del que és impropi, és estimat dels virtuosos i indesitjat dels que no ho són.",
  "78": "No vagis amb males companyies ni et facis amb els malvats; envolta't de bells amics, vés amb els excel·lents.",
  "79": "Qui s'abeura a la doctrina dorm tranquil, amb la ment clara; el savi sempre gaudeix de la doctrina dels purs.",
  "80": "Els canals porten aigua, els sageters adrecen sagetes, els fusters dobleguen la fusta; els savis es modelen ells mateixos.",
  "81": "Com una pedra sòlida que no trontolla amb el vent, així els savis no s'immuten amb l'elogi o el retret.",
  "82": "Com un estany profund, clar i transparent, en sentir els ensenyaments, els savis s'asserenen.",
  "83": "Els virtuosos renuncien a tot, els pacífics no mostren desitjos ni aversions; tocats per la fortuna o la dissort, els savis no s'alteren.",
  "84": "Qui no desitja fills, riqueses ni poder, ni per a ell mateix ni per a un altre, ni vol obtenir l'èxit amb l'engany, aquest és virtuós, just i savi.",
  "85": "N'hi ha pocs entre els homes que passin a l'altra banda; la resta de la gent corren per aquesta riba.",
  "86": "Els que segueixen l'ensenyament que se'ls ha donat, van a l'altra banda del regne de la mort, que és tan difícil de creuar.",
  "87": "Que el savi abandoni les qualitats nocives i desenvolupi les beneficioses; que deixi la casa per la vida sense llar, la solitud que és tan difícil de gaudir.",
  "88": "Que en ella trobi goig, deixant el consum de plaers; desposseït, que el savi es purifiqui de les angoixes mentals.",
  "89": "Els que entrenen bé la ment en les pràctiques de la vida desperta, que troben goig en la renúncia i el despreniment, que s'han desintoxicat, lluminosos, aquests en el món estan en pau.",
  "chap7": "L'Alliberat",
  "90": "Aquell que ha fet el camí, que no té afliccions, s'ha alliberat del tot i ha abandonat els lligams, ja no té febre.",
  "91": "Els que estan atents no es lliguen, no els plau estar al mateix lloc; van d'una casa a l'altra, com els cignes deixen els llacs.",
  "92": "Els que no fan acumulació, saben bé què els nodreix i pasturen en la llibertat buida i nua, el seu camí és difícil de seguir, com el dels ocells al cel.",
  "93": "Qui s'ha desintoxicat, no depèn dels aliments i pastura en la llibertat buida i nua, el seu camí és difícil de seguir, com el dels ocells al cel.",
  "94": "Qui té els sentits calmats, com cavalls ben domats per l'auriga, i ha deixat l'orgull i l'addicció, fins i tot els déus l'envegen.",
  "95": "Inalterable com la terra, estable com la columna d'Indra, com un llac sense fang; per a ell no hi ha repeticions.",
  "96": "Té la ment tranquil·la, tranquil·les la parla i les accions, el que s'ha calmat, alliberat per la bona comprensió.",
  "97": "L'home que és independent, que sap el que no ha de fer, que ha tallat els lligams, no fa mal i no vol res, aquest és l'home superior.",
  "98": "Sigui una vila o bé un bosc, una plana o una vall, la terra on viuen els perfectes és un lloc deliciós.",
  "99": "Als boscos deliciosos, que no freqüenta la gent, gaudeixen els que estan calmats, no els que necessiten plaers.",
  "chap8": "Milers",
  "100": "Millor que mil versos compostos de paraules vanes, és una paraula justa que dóna pau a qui l'escolta.",
  "101": "Millor que mil estrofes compostes de paraules vanes, és una sola paraula que dóna pau a qui l'escolta.",
  "102": "Millor que cent poemes compostos de paraules vanes, és un sol vers veritable, que calma el qui l'escolta.",
  "103": "Hom podria vèncer mil cops mil homes en la batalla, però qui es venç un cop ell mateix és el suprem vencedor.",
  "104": "La conquesta d'un mateix val més que la de qualsevol altre, per a l'home que sempre es domina i és amo de si mateix.",
  "105": "Ni cap déu ni semidéu, ni juntament Mara i Brahmà, podrien destruir la conquesta d'una persona així.",
  "106": "Es poden fer mil sacrificis cada mes durant cent anys; però honorar per un moment una persona transformada és una ofrena millor que cent anys de sacrificis.",
  "107": "Es pot adorar el foc al bosc durant cent anys; però honorar per un moment una persona transformada és una ofrena millor que cent anys de sacrificis.",
  "108": "Si aquell que desitja mèrit fa sacrificis al cosmos i penitències tot l'any, això no li val ni una quarta part del que val honorar els rectes.",
  "109": "Quatre coses creixen en qui té una conducta honorable i respecta els superiors: la vitalitat, la bellesa, la salut i la força.",
  "110": "Molt més que viure cent anys sense virtut i distret, val un sol dia de vida del meditador virtuós.",
  "111": "Molt més que viure cent anys arrauxat i distret, val un sol dia de vida del meditador assenyat.",
  "112": "Molt més que viure cent anys amb indolència i apatia, val un sol dia de vida de qui s'aplica a l'esforç.",
  "113": "Molt més que viure cent anys sense veure la transitorietat, val un sol dia de vida de qui veu la transitorietat.",
  "114": "Molt més que viure cent anys sense veure el que no mor, val un sol dia de vida de qui veu el que no mor.",
  "115": "Molt més que viure cent anys sense veure la veritat última, val un sol dia de vida de qui veu la veritat última.",
  "chap9": "L'Acció Nociva",
  "116": "Cal afanyar-se en el bé i apartar la ment del que és nociu, car la ment s'hi acostuma si hom és lent en els actes meritoris.",
  "117": "Si hom fa una acció nociva, que no la repeteixi que no es converteixi en hàbit!: acumular demèrit és dolorós.",
  "118": "Si hom fa una acció beneficiosa, que la repeteixi i la converteixi en hàbit: acumular mèrit és agradable.",
  "119": "El malvat s'ho passa bé mentre no madura el mal, però quan el mal madura, llavors rep el mal que ha fet.",
  "120": "El bo s'ho passa malament mentre no madura el bé, però quan el bé madura, llavors rep el bé que ha fet.",
  "121": "No s'ha de pensar del demèrit: 'Això no m'arribarà a mi'. Amb gotes d'aigua s'omple el càntir; el malvat s'omple de demèrit acumulant-lo de mica en mica.",
  "122": "No s'ha de pensar del mèrit: 'Això no m'arribarà a mi'. Amb gotes d'aigua s'omple el càntir; el savi s'omple de mèrit acumulant-lo de mica en mica.",
  "123": "Com el mercader que transporta els béns en una caravana tem el camí, com tem el verí qui vol viure, cal evitar els actes nocius.",
  "124": "Qui no té la mà ferida pot agafar-hi el verí; el verí no penetra la mà sana, no hi ha demèrit per a qui no el fa.",
  "125": "Si un home fa mal a qui no està ofuscat, s'ha transformat i no té defectes, la seva mala acció li retorna neci!, com la pols fina llançada contra el vent.",
  "126": "Alguns reneixen a l'úter, els que fan demèrit van a l'infern, els que tenen un bon destí van al cel, els que no tenen residu s'extingeixen.",
  "127": "Ni dalt del cel, ni enmig del mar, ni dins d'una cova a la muntanya, no hi ha cap lloc a la terra on s'estigui lliure d'una mala acció.",
  "128": "Ni dalt del cel, ni enmig del mar, ni dins d'una cova a la muntanya, no hi ha cap lloc a la terra fora de l'abast de la mort.",
  "chap10": "La Violència",
  "129": "Tothom tremola amb la violència, tothom tem la mort; cal posar-se al lloc de l'altre i no matar ni fer matar.",
  "130": "Tothom tremola amb la violència, tothom s'estima la vida; cal posar-se al lloc de l'altre i no matar ni fer matar.",
  "131": "Aquell que usa la violència contra els éssers que volen ser feliços, quan ho vulgui ser ell mateix, no ho podrà ser més endavant.",
  "132": "Aquell que no usa la violència contra els éssers que volen ser feliços, quan ho vulgui ser ell mateix, ho podrà ser més endavant.",
  "133": "No diguis res ofensiu, el que hagis dit se't podria dir a tu; parlar agressivament és dolorós, els cops et tocaran a tu.",
  "134": "Si no reverberes, com un gong esquerdat, has arribat a l'estat de pau; en tu no hi ha agressivitat.",
  "135": "Com el pastor porta les vaques a la pastura amb el bastó, així la vellesa i la mort porten la vida dels éssers.",
  "136": "El neci no comprèn que ha fet accions nocives; el desassenyat pateix, cremat pel foc dels seus actes.",
  "137": "Aquell que, amb la violència, fereix els innocents que no l'han agredit, ràpidament pot trobar-se en un d'aquests deu estats:",
  "138": "un fort dolor físic i la pèrdua o el trencament d'una part del cos, o bé una malaltia greu i la bogeria;",
  "139": "o bé l'atac del rei, acusacions greus, la pèrdua de parents i la disminució de les riqueses;",
  "140": "el foc, destructor, li pot cremar les possessions, i, en desintegrar-se el cos, el ximplet renaixerà a l'infern.",
  "141": "Ni nuesa, ni trenes, ni fangs, ni dejunis, ni el jeure damunt d'una pedra, ni la pols i la suor d'exercitar-se ajupit purifiquen el mortal que encara dubta.",
  "142": "Si va vestit però és equànime, calmat, dominat, controlat, cast, i deposa la violència contra les criatures, és un home superior, un asceta, un monjo.",
  "143": "¿Qui, en aquest món, censura l'home que té vergonya i es conté, i que no coneix el retret com el bon cavall no coneix el fuet?",
  "144": "Com el bon cavall, atent al fuet, sigueu amatents i ràpids a respondre. Amb confiança, virtut i energia, concentració i discerniment, seny i bona conducta, eliminareu aquesta gran angoixa.",
  "145": "Els aqüeductes porten aigua, els sageters adrecen sagetes, els fusters dobleguen la fusta; els virtuosos es modelen ells mateixos.",
  "chap11": "La Vellesa",
  "146": "¿Què és aquest riure, aquesta joia, quan tot crema constantment? ¿Esteu encegats per la foscor i no busqueu la llum?",
  "147": "Guaita la forma acolorida: un cos ple d'úlceres, altiu, malalt i ple d'angoixes, sense estabilitat perdurable.",
  "148": "S'ha fet vell aquest cos, fràgil niu de malalties, descompost en una massa corrupta: la vida s'acaba amb la mort.",
  "149": "Com les carbasses a la tardor, estan escampats aquests ossos esblanqueïts. ¿Qui troba goig a veure'ls?",
  "150": "Una ciutat feta d'ossos, un aglomerat de carn i sang: on hi ha la vellesa i la mort, no queden pretensions ni orgull.",
  "151": "Els carros reials, acolorits, envelleixen; el cos també es fa vell, però la veritat dels savis no envelleix, els savis ho demostren a tots.",
  "152": "L'home que no ha escoltat prou envelleix com un bou; li creixen les carns, però no li augmenta el seny.",
  "153": "¿Per quantes vides he passat revoltant un cop i un altre, cercant en va el constructor de la casa? Que dolorós és néixer sense parar!",
  "154": "Ara t'he vist, oh constructor! No tornaràs a aixecar la casa! Totes les bigues s'han trencat i ha caigut la pedra mestra. La ment, deconstruïda, ha assolit la fi dels desitjos.",
  "155": "Els que no han seguit l'aprenentatge i no han assolit el bé de joves, es consumeixen com aurons vells en un estany sense peixos.",
  "156": "Els que no han seguit l'aprenentatge i no han assolit el bé de joves, jeuen com arcs inútils, lamentant-se del passat.",
  "chap12": "Mateix",
  "157": "Aquell que s'aprecia ell mateix es protegeix ben protegit; el savi es manté despert una de les tres vetlles.",
  "158": "Hom ha de viure rectament en primer lloc ell mateix, i després podrà ensenyar els altres; altrament els corrompria.",
  "159": "Si hom fes amb si mateix el que vol ensenyar als altres! Qui està domat pot domar; que difícil és domar-se un mateix!",
  "160": "Cadascú és el seu propi guarda, ¿qui més el podria guardar? Aquell que es doma a si mateix té un guarda que no té preu.",
  "161": "El mal se'l fa un mateix, neix d'un mateix, és producte d'un mateix; destrueix el desassenyat com el diamant trenca la pedra.",
  "162": "Qui es deixa ofegar pels mals hàbits, com l'heura que s'enfila per l'arbre, s'està fent a si mateix el que un enemic li faria.",
  "163": "Fàcils són les accions insanes, nocives per a un mateix; allò que és sa i beneficiós és, per contra, de mal fer.",
  "164": "La instrucció dels perfectes, dels nobles que viuen en la veritat, la menysprea el desassenyat que té idees errònies; com el bambú, fructifica per autodestruir-se.",
  "165": "Un mateix fa el mal, un mateix es contamina, un mateix deixa de fer el mal, un mateix es purifica; contaminació i purificació pertanyen a cadascú; ningú no pot purificar l'altre.",
  "166": "No s'ha de deixar de banda el propi deure pel d'un altre, per molt important que sigui; cal conèixer el propi deure i dedicar-s'hi.",
  "chap13": "Mons",
  "167": "No s'ha de tenir mals costums ni avesar-se a estar distret, no s'ha de seguir males doctrines ni anar amb el comú de la gent.",
  "168": "S'ha d'estar alerta i no distreure's, s'ha de tenir una bona conducta; qui té una bona conducta dorm bé en aquest món i en l'altre.",
  "169": "S'ha de tenir una bona conducta i evitar la mala conducta; qui té una bona conducta dorm bé en aquest món i en l'altre.",
  "170": "Aquell que contempla el món com si fos una bombolla, com si fos un miratge, el Rei de la Mort no el veu.",
  "171": "Guaiteu aquest món, acolorit com un carro reial: els necis hi viatgen, però els savis el deixen passar.",
  "172": "Aquell que abans es distreia i ara no es deixa emportar, il·lumina aquest món com la lluna quan els núvols s'esvaeixen.",
  "173": "Aquell que cobreix el mal que ha fet amb una acció beneficiosa, il·lumina aquest món com la lluna quan els núvols s'esvaeixen.",
  "174": "Aquest món està encegat, la minoria hi veu clar; són pocs els que van al cel, com ocells alliberats de la gàbia.",
  "175": "Els cignes van pel camí del sol, els mags van per l'espai; els savis deixen el món conquerint Mara i el seu exèrcit.",
  "176": "Per a la persona que menteix que ha faltat una llei sola, quan traspassa a l'altre món, no hi ha mal que es pugui desfer.",
  "177": "Els gasius no van al món dels déus, la generositat per al neci no és res; però el savi, que dona amb alegria, és feliç al més enllà.",
  "178": "Més que poder regnar damunt tota la terra, anar al cel, o dominar tots els mons, val el fruit de l'entrada al corrent.",
  "chap14": "Desperts",
  "179": "La seva victòria no es pot desfer, la seva victòria no va enlloc… Aquell que està despert i es mou en l'infinit sense deixar traça, ¿per quin camí el seguireu?",
  "180": "No té desig que l'atrapi, que l'enganxi o el dugui enlloc… Aquell que està despert i es mou en l'infinit sense deixar traça, ¿per quin camí el seguireu?",
  "181": "Els savis que s'apliquen a la meditació, acostumats a la calma de la renúncia, fins i tot els déus els envegen, perquè estan desperts i atents.",
  "182": "És difícil néixer humà, difícil la vida dels mortals, difícil escoltar l'ensenyament veritable, difícil que apareguin éssers desperts.",
  "183": "Abstenir-se d'accions nocives, fer allò que és beneficiós i purificar els pensaments; això és el que ensenyen els desperts.",
  "184": "La paciència és l'austeritat màxima, l'acceptació l'absència de desig suprema diuen els desperts. No és monjo qui mata l'altre, ni asceta qui li fa mal.",
  "185": "No criticar, no cometre violència, seguir la regla monàstica, ésser mesurat en l'aliment, jeure i seure en solitud i practicar la meditació; això és el que ensenyen els desperts.",
  "186": "Ni acompanyats d'una pluja de monedes els plaers podrien satisfer. 'Els plaers són penosos i insípids' així reflexiona el savi.",
  "187": "Ni tan sols troba gust en els plaers dels déus; el deixeble del Ben Despert gaudeix de la fi de la set.",
  "188": "Molts van a refugiar-se a les muntanyes i als boscos, a ermites, arbres i temples: homes acovardits!",
  "189": "No és aquest el refugi segur, no és aquest el suprem refugi; aquell que s'hi refugia no s'allibera del sofriment.",
  "190": "Qui ha pres refugi en el Despert, en l'Ensenyament i en la Comunitat, veu amb la intel·ligència les quatre nobles veritats:",
  "191": "el sofriment, el sorgiment del sofriment, la superació del sofriment i el noble òctuple camí que apaivaga el sofriment.",
  "192": "Aquest sí que és el refugi segur, aquest és el suprem refugi; aquell que s'hi refugia s'allibera del sofriment.",
  "193": "Un home de bona casta és difícil de trobar, no en neixen a tot arreu! Feliç prospera la família on neix un home intel·ligent.",
  "194": "Benaurada l'aparició d'éssers desperts, benaurat l'ensenyament veritable, benaurada l'harmonia de la comunitat, benaurat el caliu dels que estan units.",
  "195": "Els desperts o els que els escolten són dignes de devoció; han superat les obsessions i han travessat l'aiguat de les penes.",
  "196": "Qui honora els que són així, immutables i lliures de la por, té un mèrit sense mesura; ningú no pot dir: 'fa tant'",
  "chap15": "Feliços",
  "197": "Oh, que feliços vivim, sense odi entre els que odien! Entre els homes que s'odien, nosaltres vivim sense odi!",
  "198": "Oh, que feliços vivim, sense aflicció entre els afligits! Entre els homes afligits, nosaltres vivim sense aflicció!",
  "199": "Oh, que feliços vivim, sense afanys entre els que s'afanyen! Entre els homes que s'afanyen, nosaltres vivim sense afanys!",
  "200": "Oh, que feliços vivim, nosaltres que no tenim res! Ens alimentem de joia, com els déus radiants!",
  "201": "El vencedor genera odi, el derrotat dorm adolorit; el que està en pau dorm tranquil, perquè no té victòries ni derrotes.",
  "202": "No hi ha foc com el de l'atracció, no hi ha transgressió com l'aversió, no hi ha sofriments com els de l'existència, no hi ha felicitat més gran que estar calmat.",
  "203": "La fam és la pitjor malaltia, les emocions el pitjor sofriment; per a qui veu això tal com és, l'estat de pau és la més gran benaurança.",
  "204": "La salut és el bé més gran, el contentament la major riquesa, la confiança és el millor amic, l'estat de pau, la felicitat màxima.",
  "205": "Qui ha tastat el gust de la discriminació i de la calma, no fa el mal ni té cap por, perquè ha tastat la joia de la veritat.",
  "206": "Visitar els nobles és bo, conviure-hi sempre és agradable; sense fer-se amb la gent nècia, hom pot ser sempre feliç.",
  "207": "Qui es relacioni amb els necis es lamentarà molt temps! Viure amb necis és penós com estar sempre amb l'enemic; estar acompanyat de savis és com reunir-se amb els parents.",
  "208": "Un home resolt, savi, entès, de virtuts fermes, noble i fidel, íntegre i assenyat: cal seguir-lo, com la lluna segueix el camí de les estrelles.",
  "chap16": "Que és Plaent",
  "209": "Aquell que s'acostuma a la indisciplina i no s'aplica a l'esforç, quan abandona les obligacions i es dedica al que li plau, enveja els que compleixen el seu deure.",
  "210": "Hom no ha de jutjar mai què és agradable o desagradable: és penós no tenir el que és agradable o que arribi el que no ho és.",
  "211": "Per tant, cal no considerar res agradable: separar-se del que és agradable és un mal. Els que no consideren res agradable ni desagradable estan deslligats.",
  "212": "El que és agradable provoca neguit, el que és agradable és un perill; qui deixa anar el que és agradable no té neguit, ¿quin perill corre?",
  "213": "El que és plaent provoca neguit, el que és plaent és un perill; qui deixa anar el que és plaent no té neguit, ¿quin perill corre?",
  "214": "L'afecció provoca neguit, l'afecció és un perill; qui deixa anar l'afecció no té neguit, ¿quin perill corre?",
  "215": "El plaer provoca neguit, el plaer è un perill; qui deixa anar el plaer no té neguit, ¿quin perill corre?",
  "216": "El voler provoca neguit, el voler és un perill; qui deixa anar el voler no té neguit, ¿quin perill corre?",
  "217": "Aquell que té virtut i perspicàcia, compleix el deure amb fermesa i veu la realitat amb certesa; si fa la seva feina, la gent se l'estima.",
  "218": "Aquell en qui ha nascut el desig d'aprendre, està ple d'aquesta aspiració i no pensa en els plaers dels sentits, s'anomena 'un que va a contracorrent'.",
  "219": "Quan un home torna sa i estalvi després de viure lluny molt temps, els parents i els amics s'alegren de la seva arribada.",
  "220": "Igualment, si hom fa mèrits, quan passa d'aquest món a l'altre, els seus mèrits el reben com els parents acullen l'estimat que arriba.",
  "chap17": "La Ira",
  "221": "Si hom elimina la ira, abandona l'orgull, transcendeix tota seguretat, no s'adhereix als conceptes i no considera res seu, els sofriments no l'atrapen.",
  "222": "Qui pot aturar la ira que ha sorgit com si fos un carro desbocat, aquest, l'anomeno auriga; els altres s'agafen a les regnes.",
  "223": "La ira es venç amb l'absència d'ira, amb el bé es venç el que no està bé, donant es venç la gasiveria i amb la veritat, la falsedat.",
  "224": "Qui diu la veritat, no s'enfada, i dóna a qui demana encara que sigui poc; amb aquestes tres condicions es pot presentar davant dels déus.",
  "225": "Els ascetes en qui no hi ha violència, amb el cos sempre controlat, van a un lloc immutable on qui hi ha anat ja no es lamenta.",
  "226": "Per als que es mantenen desperts i dia i nit aprenen, determinats a arribar a l'estat de pau, les dificultats desapareixen.",
  "227": "Això és cosa antiga, Atula, tant com és dels d'avui: critiquen qui seu en silenci, critiquen qui parla molt, critiquen qui parla poc. No hi ha ningú a qui no critiquin en aquest món.",
  "228": "No hi ha hagut ni hi haurà, i tampoc ara no hi ha, cap home del tot blasmable ni del tot lloable.",
  "229": "Aquell a qui els assenyats lloen, quan l'han vist quotidianament, d'hàbits ferms, assenyat, acomplert en conducta i comprensió,",
  "230": "com una moneda d'or, ¿qui gosaria criticar-lo? Fins i tot els déus el lloen, fins i tot el lloa Brahmà!",
  "231": "Cal guardar-se de l'agitació corporal i mantenir el cos dominat; cal deixar el mal comportament corporal i utilitzar bé el cos.",
  "232": "Cal guardar-se de l'agitació verbal i mantenir la veu dominada; cal deixar el mal comportament verbal i utilitzar bé la paraula.",
  "233": "Cal guardar-se de l'agitació mental i mantenir la ment dominada; cal deixar el mal comportament mental i utilitzar bé la ment.",
  "234": "Els savis dominen el cos i després dominen la paraula; però quan dominen la ment, certament ho dominen tot.",
  "chap18": "Defectes",
  "235": "Ets com una fulla seca, els servents de Yama t'esperen; has d'emprendre la tasca, però no duus provisions.",
  "236": "Fes-te una illa a tu mateix, esforça't de pressa! i esdevingues savi; quan hagis eliminat els teus defectes, immaculat, arribaràs a la divina terra dels nobles.",
  "237": "Has complert el temps, has arribat davant de Yama; no et queda temps de vida i no duus provisions.",
  "238": "Fes-te una illa a tu mateix, esforça't de pressa! i esdevingues savi; quan hagis eliminat els teus defectes, immaculat, no tornaràs a passar pel naixement i la vellesa.",
  "239": "L'assenyat, a poc a poc, de mica en mica, poleix els seus defectes, un rere l'altre, com l'orfebre treballa l'argent.",
  "240": "Igual que polint un defecte del ferro hom pot fer malbé el material d'on l'extreu, aquell que és massa estricte fa accions que el duen a un mal destí.",
  "241": "El mantra mal après és defectuós, la casa té defectes si no es cuida, l'ornament és defectuós si hom té peresa, i, per al vigilant, la distracció és un defecte.",
  "242": "La deixadesa és el defecte de la dona, l'avarícia el defecte del donant: els defectes són mala cosa en aquest món i en l'altre.",
  "243": "Però hi ha un defecte molt més gran que aquests: la ignorància és el major defecte; abandoneu aquest defecte i sigueu purs, oh monjos!",
  "244": "La vida és fàcil per a qui no té vergonya, és agosarat com un corb, ofensiu, avassallador, arrogant i corrupte;",
  "245": "però difícil per al vergonyós, que constantment aspira a la puresa, viu sol i amb senzillesa, fa una vida íntegra i és perspicaç.",
  "246": "Qui occeix els éssers que respiren, parla amb falsedat, pren el que no li donen, va amb la dona d'altri,",
  "247": "i s'afecciona a la beguda, aquí mateix en aquest món talla la seva pròpia rel.",
  "248": "Així doncs, sàpigues, home, que la manca de domini és nociva; que la cobdícia i el desordre no et subjectin gaire més temps al sofriment.",
  "249": "La gent dóna segons creuen i segons els va bé; aquell que es posa gelós de la beguda i el menjar dels altres no té calma mental ni de dia ni de nit.",
  "250": "Però aquell que ho elimina, ho talla, ho arrenca de socarrel, pot tenir calma mental tant de dia com de nit.",
  "251": "No hi ha foc com el de la passió, ni cap captiveri com el de l'odi, no hi ha xarxa com la de la il·lusió, ni riu com el del desig.",
  "252": "El defecte aliè és fàcil de veure, però és difícil veure el propi; les faltes dels altres s'airegen com la pellofa del gra, però les d'un mateix s'amaguen com una mala tirada de daus.",
  "253": "Si hom es fixa en les faltes dels altres i els critica constantment, es va intoxicant a si mateix, és lluny de destruir l'addicció.",
  "254": "A l'espai no hi ha camí, hom no és asceta al defora; la gent gaudeix de les complicacions, els que viuen el present se n'han desprès.",
  "255": "A l'espai no hi ha camí, hom no és asceta al defora; no hi ha emocions eternes, ni pertorbació en els desperts.",
  "chap19": "El Just",
  "256": "Molts jutgen a la lleugera no recolzant-se en el Dharma, però el savi hauria d'investigar tant el just com l'injust.",
  "257": "Qui guia als altres amb imparcialitat, acuradament, d'acord al Dharma, és el protector del Dharma, el coneix i és designat com autoritat.",
  "258": "Tan sols per articular sons amb la veu un no es converteix en savi. Tot gaudint de seguretat, qui és lliure d'odi i por, a aquest se'l considera 'savi'.",
  "259": "Tan sols per articular sons amb la veu un no es torna versat en el Dharma, però aquell que, havent-lo escoltat, encara que sigui poc, el practica diligentment, aquest realment és 'versat en el Dharma'.",
  "260": "L'home no és un venerable ancià únicament per tenir el cabell canós; podria ser algú que ha envellit i prou, algú que ha envellit en va.",
  "261": "Qui és just i veraç, no violent, prudent i disciplinat, qui ha eliminat les contaminacions, aquest és un venerable ancià.",
  "262": "No és per l'eloqüència, o per la seva bella aparença, que un es converteix en una bella persona, si, a més, és gelós, jactanciós i mesquí.",
  "263": "Qui realment és 'bell', és qui ha desarrelat les contaminacions, les ha destruït per complet, un home savi que ha eliminat l'odi.",
  "264": "Tan sols per afaitar-se el cap, un no es converteix en un bon practicant, si segueix sent mentider i indisciplinat. Qui cobeja i és ple de desitjos, ¿com podria ser un bon aprenent?",
  "265": "Qui ha subjugat tota la maldat, ha eradicat totes les males accions, petites i grans, aquest és un veritable practicant del Dharma.",
  "266": "Encara que un hagi de pidolar almoines, no per això es converteix en monjo; només qui practica el Dharma mereix aquest nom.",
  "267": "Qui ha transcendit el bé i el mal, ha viscut la vida santa i ha superat el món mundà, aquest és realment un monjo.",
  "268": "El mer silenci no el fa a un savi, quan s'és ignorant i extraviat; però sospesar tot i optar només pel que és noble, porta com a benedicció la saviesa.",
  "269": "Qui fa conscient el món intern i el món extern havent adquirit aquesta saviesa, es desfà del mal per complet, és un veritable savi.",
  "270": "El que danya als éssers vius no pot ser un home noble; només el respecte per la vida el fa a un digne d'aquest nom.",
  "271": "No és a través dels vots i els rituals, no per llegir molt ni per aconseguir la calma meditativa, tampoc per viure reclòs;",
  "272": "Res d'això és suficient perquè el practicant pugui dir: 'He experimentat la joia del 'deixar anar', que és negada a la gent comuna', si encara no s'ha alliberat de totes les contaminacions.",
  "chap20": "El Camí",
  "273": "Dels camins a seguir, l'óctuple és el millor, i dels principis, les quatre nobles veritats. El desaferrament és el millor ensenyament, i el millor dels homes és el Despert.",
  "274": "Aquest és el camí, no n'hi ha cap altre per aquí, per tal de purificar la visió; si un entra en aquest Camí, descol·loca al Mara per complet.",
  "275": "Entreu, doncs, en el Camí, poseu fi a la insatisfacció. Lliure de nusos i punxes per mitjà del coneixement, jo mateix proclamo el Camí.",
  "276": "Els Budes tan sols indiquen el camí, però sou vosaltres els que heu de practicar i seguir-lo; els meditadors que segueixen aquest Camí, s'alliberen plenament de les urpes del Mara.",
  "277": "Quan un descobreix amb saviesa que totes les coses condicionades són transitòries, es desprèn del cansament de la insatisfacció i fa un pas en el camí de la puresa.",
  "278": "Quan un descobreix amb saviesa que totes les coses condicionades són doloroses, es desprèn del cansament de la insatisfacció i fa un pas en el camí de la puresa.",
  "279": "Quan un descobreix amb saviesa que totes les coses condicionades no són essencials, un es desprèn del cansament de la insatisfacció i fa un pas en el camí de la puresa.",
  "280": "El que no s'esforça quan arriba el moment de fer-ho, que és indolent sent encara jove i fort, amb la ment feble i sense objectiu clar, no trobarà el camí de la saviesa.",
  "281": "Sempre vigilant del que un diu i amb la ment calmada, evitant accions corporals perjudicials: Així un hauria de preservar les tres portes del karma per avançar en el camí.",
  "282": "Certament, de la meditació brolla la saviesa, mentre que la mateixa s'esvaeix quan no es medita; havent conegut aquesta doble via, la del progrés i el declivi, un hauria d'esforçar-se per incrementar la saviesa.",
  "283": "Talleu el bosc sencer i no solament un arbre, perquè és el bosc on s'origina la por. Havent tallat el bosc amb les males herbes de les passions, sereu veritables monjos que aconsegueixen el Nirvana.",
  "284": "I mentre el bosc no sigui tallat, el més mínim desig de l'home cap a la dona encadenarà la seva ment com la lletera que rau lligada a la seva mare vaca.",
  "285": "Arrenca l'afecte cap a tu mateix, com s'arrenca la lila de la tardor. Conrea el camí de la pau i el Nirvana ensenyat pel despert.",
  "286": "'Aquí passaré l'estació de les Pluges, allí l'hivern i allà l'estiu'. Així planifica el ximple, inconscient de tot perill.",
  "287": "Qui viu amb la ment aferrada, cercant delit en els fills i els ramats, serà enganxat per la mort i escombrat, com quan un poble dormit és arrossegat per una gran inundació.",
  "288": "Els fills no ofereixen cap refugi, els pares i la família tampoc; per a algú enxampat per la mort, no hi ha refugi en el parentiu.",
  "289": "Havent entès això, el savi es concentra en la virtut, i amb diligència esclareix el camí que condueix al Nirvana.",
  "chap21": "Miscellània",
  "290": "Si s'albira una gran felicitat desistint a una de no tan gran, l'home savi renuncia a la darrera per aconseguir la primera.",
  "291": "Qui desitja felicitat per a si mateix causant penes als altres, ple d'ira, mai serà alliberat de l'odi.",
  "292": "El que hauria de fer-se no es fa, i mentre es fa allò que no hauria de fer-se, s'incrementen les impureses dels arrogants i els negligents.",
  "293": "Però els que practiquen persistentment, conscientment atents del cos, aquells que mai fan l'indegut sinó que sempre s'obstinen en l'acció justa, aquells que estan atents i són conscients, fonen totes les impureses.",
  "294": "Havent donat mort a la seva mare [avidesa] i al seu pare [egocentrisme], havent assassinat als dos reis guerrers [eternalisme i nihilisme], havent destruït els seus regnes amb els súbdits, un camina immune, com un sant.",
  "295": "Havent donat mort a la seva mare [avidesa] i pare [egocentrisme], havent assassinat als dos reis guerrers [eternalisme i nihilisme], havent destruït en el camí feres salvatges, un camina immune, com un sant.",
  "296": "Els deixebles del Buda són aquells que constantment, dia i nit, romanen meditant sobre les virtuts del Buda.",
  "297": "Els deixebles del Buda són aquells que constantment, dia i nit, romanen meditant sobre les virtuts del Dharma.",
  "298": "Els deixebles del Buda són aquells que constantment, dia i nit, romanen meditant sobre les virtuts del Sangha.",
  "299": "Els deixebles de Buda són aquells que constantment, dia i nit, romanen meditant sobre la naturalesa del cos.",
  "300": "Els deixebles de Buda són aquells que constantment, de dia i de nit, romanen meditant en el delit de l'innocu.",
  "301": "Els deixebles del Buda són aquells que constantment, dia i nit, troben delit en la meditació.",
  "302": "Difícil és la renúncia i difícil és delectar-se en ella, difícil és la vida en la llar, ja que també produeix penes, penós és associar-se amb persones incompatibles, penós és recórrer el samsara. Per això no us quedeu atrapats viatjant pel samsara, deixeu de perseguir l'insatisfactori.",
  "303": "Aquell que està ple de confiança i virtut, dotat de glòria i riqueses, és honrat per tothom, onsevulla que vagi.",
  "304": "Els homes pacificadors brillen des de lluny, com la nevada cúspide d'Himàlaia, mentre que els homes falsos desapareixen, són com fletxes disparades en la nit.",
  "305": "En solitud un seu, en solitud es fica al llit, en solitud camina i camina; en solitud un s'entrega a si mateix i trobarà delit en el bosc.",
  "chap22": "L'Infern",
  "306": "Qui nega la veritat va a l'infern, igual que aquell que ha fet alguna cosa i nega haver-la fet. Tots dos, per igual, pagaran per les seves accions en l'altra vida.",
  "307": "Molts que porten l'hàbit groc i no restringeixen les seves males accions, són malvats i, gràcies al seu mal karma, renaixeran en futures vides infernals.",
  "308": "Seria millor empassar una bola d'acer, ardent com una flama, que menjar el menjar de les almoines si algú és immoral i no se sap contenir.",
  "309": "Quatre coses li succeïxen a l'home negligent que es fica al llit amb les esposes dels altres: demèrit, insomni, sentiment de culpa i l'infern.",
  "310": "El no-mèrit i una mala destinació per un fugaç plaer de l'espantat amb l'espantada. A més, està el rei qui els imposa un dur càstig: per això ningú hauria de ficar-se al llit amb les esposes dels altres.",
  "311": "Igual que un bri d'herba talla la mà quan està mal adreçada, així també la vida monàstica mal enfocada condueix al patiment.",
  "312": "Un mèrit fet casualment, una pràctica corrompuda, la vida santa dubtosa: res d'això produeix fruits duradors.",
  "313": "Si hi ha alguna cosa meritòria que ha de ser feta, cal realitzar-la diligentment; però una vida monàstica dubtosa certament afegeix més pols de la que hi havia abans.",
  "314": "És millor evitar una mala acció, perquè el que ha estat mal fet no es converteixi en turment. És millor fer el correcte: no hi ha turments quan es fa el bé.",
  "315": "Igual que les fronteres de la ciutat que estan custodiades per dins i per fora, així hauria de protegir-se un mateix. No deixis passar aquest moment, perquè si et distreus hi haurà aflicció i l'infern.",
  "316": "Hi ha qui s'avergonyeix quan no hi ha de què, però no ho fa quan es tracta de fets vergonyosos; aquest, per haver abraçat un punt de vista incorrecte, anirà directe a un mal renaixement.",
  "317": "Hi ha qui s'atemoreix quan no hi ha de què, però no ho fa quan es tracta de fets temibles; aquest, per haver abraçat un punt de vista incorrecte, anirà directe a un mal renaixement.",
  "318": "Hi ha qui veu mancança on no n'hi ha, però quan realment quelcom falla no ho veu així; aquest, per haver abraçat un punt de vista incorrecte, va directe a un mal renaixement.",
  "319": "Hi ha qui coneix la falta com a tal, igual que reconeix quan no n'hi ha; aquest, per haver abraçat un punt de vista correcte, va directe a un renaixement feliç.",
  "chap23": "L'Elefant",
  "320": "La majoria de la gent no és virtuosa, però jo vaig a suportar l'abús, com ho fa un elefant enmig de la batalla quan li disparen les fletxes.",
  "321": "L'elefant ensinistrat condueix la rajada, sobre ell cavalca el rei; els més nobles entre els homes són aquells que són receptius, entregats i atents, i saben resistir els abusos.",
  "322": "Excel·lents són les mules domades, i els cavalls de pura raça de Sind, i els nobles elefants de l'Estat; però el millor de tots els homes és qui s'ha ensinistrat a si mateix.",
  "323": "Muntant aquesta classe de vehicles un no pot abastar el Nirvana; només entrenant-se a si mateix un adquireix el vehicle correcte.",
  "324": "Quan l'elefant Dhanapalaka està encadenat, no menja ni un mos i és incontrolable: es comporta com si estigués en zel, recordant amb nostàlgia la seva vida lliure en el bosc.",
  "325": "Un ximple ple de golafreria adormit i empastifat com un porc farcit que s'alimenta amb porqueria, renaixerà una vegada i una altra.",
  "326": "Anteriorment, aquesta erràtica ment vagava per on li plaïa; però ara l'he controlat sàviament, com un entrenador controla a l'elefant en zel.",
  "327": "Delecteu-vos en l'atenció i calmeu les vostres ments. Sortiu del camí pantanós, com ho faria un elefant enfonsat en el fang.",
  "328": "Si en la pràctica del Dharma un troba a un amic prudent, savi i de bona conducta, atent i feliç, superarà tots els problemes vivint amb ell.",
  "329": "Si a l'hora de la pràctica un no troba a un amic prudent, savi i de bona conducta, desaferrat com el rei que abandona el país conquerit, o com un elefant que es passeja solitari en el bosc,",
  "330": "millor és viure sol. No hi ha amistat possible amb un ximple. Evitar el mal i estar lliure de preocupacions és el millor, com l'elefant que es passeja solitari pel bosc.",
  "331": "Benaurat és qui té amics quan els necessita, benaurat és qui sap acontentar-se amb qualsevol cosa, benaurat és el mèrit a l'hora de la mort, benaurat el que ha abandonat la insatisfacció.",
  "332": "Respectar la mare porta felicitat, i el respecte al pare. Porta felicitat el respecte als anacoretes i eremites, igual que el respecte als sants virtuosos.",
  "333": "Benaurat sigui el virtuós fins a la fi dels seus dies, benaurat sigui el que té una fe fermament assentada, benaurat sigui el que ha guanyat saviesa, benaurat sigui el que s'absté de fer el mal.",
  "chap24": "Avidesa",
  "334": "Com l'heura trepadora, creix l'avidesa en algú que viu distret. Aquesta persona transmigra d'una vida a l'altra, com el mico en el bosc cercant fruita.",
  "335": "Tot ésser infeliç del món que es troba aferrat a l'avidesa, veu créixer les seves penes, com l'herba xopa creix després de la pluja.",
  "336": "Però aquell que, en aquest món, domina l'avidesa, que és tan difícil de ser desarrelada, veu caure les seves penes, com les gotes d'aigua que llisquen sobre les fulles del lotus.",
  "337": "Hi haurà prosperitat entre vosaltres dins les assemblees. Extirpeu l'avidesa, com es fa amb les perfumades arrels d'herba. No feu fallida de nou una vegada i una altra com si fóssiu joncs arrossegats pel Mara.",
  "338": "Igual que un arbre tallat creix de nou quan les seves arrels són fermes i estan sanes, de la mateixa manera, la insatisfacció retorna, mentre l'avidesa latent encara no ha estat extirpada.",
  "339": "Algú que és arrossegat poderosament pels trenta-sis corrents que porten cap al que aparenta ser dolç, els pensaments que brollen de la cobdícia l'arrosseguen i mantenen les actituds perjudicials.",
  "340": "Per tot arreu s'arremolinen aquests corrents, i l'heura desborda, fermament arrelada. Quan veieu plantes trepadores de l'avidesa aquí, talleu-les de soca-rel amb saviesa.",
  "341": "Els éssers s'ofeguen en les pantanoses corrents del desig; xopats en el confort, cerquen la felicitat: aquestes persones naixeran i envelliran.",
  "342": "Els que estan lligats a l'avidesa tremolen aterrits com la llebre en el parany; atrapats per les lligadures i les cadenes, viuen insatisfets durant molt temps.",
  "343": "Els que estan atrapats per l'avidesa tremolen aterrits com la llebre en el parany; per això, qui controla l'avidesa remunta lleuger envers el desaferrament.",
  "344": "Va abandonar el bosc [dels desitjos], era feliç en el bosc, però ha retornat al principi; mireu-lo ara: era lliure i ha tornat a ser esclau.",
  "345": "No són més fortes les cadenes de ferro, de fusta o de corda, proclama el savi, sinó l'apassionada ànsia pels fills, les dones, les pedres precioses i els ornaments.",
  "346": "Aquests lligams són tan forts, proclama el savi, que t'arrosseguen cap al fons i són difícils d'esquivar. No obstant això, els renunciants dominen aquestes passions i abandonen els plaers sensuals.",
  "347": "Els que romanen atrapats en les passions cauen un cop i un altre, i giren com l'aranya dins de la seva pròpia xarxa. Però els que renuncien, controlen aquesta passió i s'alliberen de la insatisfacció.",
  "348": "Deixeu anar el passat, deixeu anar el futur, deixeu anar el present: aneu més enllà de l'esdevenir. Amb la ment alliberada per complet, no hi haurà més naixements ni vellesa per a vosaltres.",
  "349": "Aquell que agita la seva ment amb dubtes i suspicàcies, i s'apassiona pels plaers sensuals, augmenta l'avidesa i les seves cadenes es tornen més fortes que mai.",
  "350": "Però qui calma els seus pensaments, i conrea l'atenció conscient en el que és caducer, eradica l'avidesa i s'alliberera de les cadenes del Mara.",
  "351": "Qui ha aconseguit la meta sense pors, roman lliure d'avidesa i culpa, va eliminar les espines de la vida i aquesta serà la seva última existència.",
  "352": "Qui roman lliure d'avidesa i aferrament, versat en l'etimologia i el significat, hàbil en les seqüències de paraules i les seves combinacions, aquest savi és anomenat 'Gran Persona' i aquesta és la seva última existència.",
  "353": "Més enllà de tots els éssers, coneixedor de tots els dharmes dels tres temps, sense aferrament i lliure de tota avidesa, havent entès tot per mi mateix: ¿a qui hauria d'anomenar jo 'mestre'?",
  "354": "El regal del Dharma supera a tots els presents, el sabor del Dharma és millor que qualsevol altre gust, el delit en el Dharma és més excels que qualsevol altre plaer, i la destrucció de l'avidesa conquereix tot allò que és negatiu.",
  "355": "Les riqueses destrueixen al ximple, a aquell que no cerca l'altra riba; àvid per les riqueses, aquest ignorant està arruïnat i arruïna als altres.",
  "356": "La zitzània és la ruïna dels camps i la passió és la ruïna dels homes; només allò que es dóna desaferradament produeix abundants fruits.",
  "357": "La zitzània és la ruïna dels camps i l'odi és la ruïna dels homes; només el que es dóna sense odi produeix abundants fruits.",
  "358": "La zitzània és la ruïna dels camps i l'engany és la ruïna dels homes; només el que es dóna sense engany produeix abundants fruits.",
  "359": "La zitzània és la ruïna dels camps i la cobdícia és la ruïna dels homes; només el que es dona sense cobdícia produeix abundants fruits.",
  "chap25": "El Deixeble",
  "360": "Autocontrolar la vista és bo, bo és autocontrolar l'oïda, autocontrolar l'olfacte és bo i bo és autocontrolar el gust.",
  "361": "Autocontrolar el tacte és bo, bo és autocontrolar la parla, autocontrolar la ment és bo i bo és autocontrolar-ho tot. El practicant que domina completament els sentits, s'allibera de tota insatisfacció.",
  "362": "Controlant les mans, els peus i la parla, dotat de la més alta autocontenció, delectant-se interiorment en el recolliment, content en la solitud: a aquest l'anomeno 'monjo'.",
  "363": "Quan la parla del meditador està sota control, quan s'expressa sàviament i sense petulància, quan explica bé tant la teoria com la pràctica, les seves paraules són dolces com la mel.",
  "364": "El practicant que adopta el Dharma com a forma de vida, en el Dharma es delecta i medita en ell, i que sempre el té present, no s'extravia mai del Noble Ensenyament.",
  "365": "Un no ha de menysprear el que ha rebut ni envejar el que reben els altres; el meditador que és envejós no aconseguirà la calma mental.",
  "366": "Encara que rebi poc, el practicant no ho menysprea; pur i diligent, rep lloances fins i tot dels déus.",
  "367": "Per qui no existeix cap 'meu' entre els noms i les formes, qui no s'aferra a res que no és, realment pot ser anomenat 'monjo'.",
  "368": "El monjo que roman en l'amor benvolent, que es delecta en l'Ensenyament del Buda, aconsegueix la Pau: la fi de tot el condicionat.",
  "369": "Buida, oh monjo, aquest pot: descarregat, seràs més veloç. Havent tallat la cobdícia i l'odi, viatjaràs cap al Nirvana.",
  "370": "Acaba amb les cinc coses i abandona les altres cinc, i unes cinc coses més conrea; el practicant que és alliberat de les cinc cadenes és anomenat 'El que creua el corrent'.",
  "371": "Medita amic, no et distreguis; no deixis que els plaers dominin en la teva ment. No permetis que per viure distret siguis empassat com una bola d'acer, i exclamis: 'quin sofriment!'",
  "372": "No hi ha jhanas sense saviesa ni hi ha saviesa sense jhanas: però algú que desenvolupa ambdues qualitats s'apropa al Nirvana.",
  "373": "El practicant que cerca un indret solitari, el cor del qual roman en pau i veu el Dharma rectament, coneix la incomparable joia.",
  "374": "Quan un reflexiona sobre sorgir i desaparèixer dels khandhas, aconsegueix interiorització i goig: l'Immortal és per a aquell que coneix.",
  "375": "Això és el principal per a un monjo savi: el control dels sentits, el conformar-se, la restricció d'acord a les regles de conducta monàstica i la companyia dels nobles amics, aquells de vida pura i diligent.",
  "376": "Sent cordial i de conducta amable, un aconsegueix un goig grandiós i posa fi a la insatisfacció.",
  "377": "Igual que les flors del gessamí es marceixen i cauen, així també, oh company, deixa caure la cobdícia i l'aversió.",
  "378": "El practicant de cos i parla calmada, serè de ment, que ha renunciat als plaers mundans, és 'perfectament tranquil'.",
  "379": "Exhorta't a tu mateix, restringeix-te a tu mateix; cuida't a tu mateix i sigues atent: així, oh germà, viuràs feliç.",
  "380": "Un mateix és el seu propi refugi i un mateix és el seu propi guia, per això un hauria de controlar-se a si mateix com els mercaders ho fan amb els seus més esplèndids cavalls.",
  "381": "Ple de goig i de fe, delectant-se en l'Ensenyament del Buda, el monjo arribarà al Lloc de la Pau, al cessament de tot el condicionat.",
  "382": "Certament, aquell jove aprenent, quan practica l'Ensenyament del Buda, illumina el món sencer com la lluna en una nit sense núvols.",
  "chap26": "El Brahman",
  "383": "Esforça't i creua el corrent dels desitjos sensorials, oh brahman; comprenent el cessament del condicionat, sigues el coneixedor del no creat.",
  "384": "Mitjançant dues qualitats, la tranquil·litat i la visió (samatha i vipassana), el brahman aconsegueix el més enllà. Tots els lligams del que coneix desapareixen per complet.",
  "385": "Per qui no existeix riba llunyana ni propera, que no es troba ni lluny ni a prop, lliure de por i taques: a aquest l'anomeno veritable brahman.",
  "386": "Assegut en contemplació, concentrat, qui ha realitzat la tasca i s'ha alliberat de les contaminacions, havent aconseguit la fita més alta: a aquest l'anomeno veritable brahman.",
  "387": "El sol brilla de dia, la lluna il·lumina de nit; brilla l'armadura del guerrer i el brahman brilla en la contemplació. No obstant això, per sobre de tot, de dia i de nit, brilla la radiant llum del Buda.",
  "388": "Perquè ha eliminat la maldat és anomenat 'brahman', perquè viu serè és anomenat 'monjo', havent bandejat les impureses se'l coneix com 'aquell que renuncia'.",
  "389": "Un no hauria d'atacar a un brahman ni aquest hauria de ser venjatiu; és una bajanada atacar a un brahman, però pitjor és que el brahman vulgui venjar-se.",
  "390": "No és petita la recompensa del brahman que aparta la seva ment del que més desitja. Mentre més s'allunya de causar dany, més amaina la seva insatisfacció.",
  "391": "En aquell en qui no es troba mal comportament de cos, de paraula o de ment, qui es restringeix en aquests tres aspectes: a aquest l'anomeno un veritable brahman.",
  "392": "A aquell que comprèn el Dharma ensenyat per un perfecte Buda, a aquest cal honrar amb devoció com el brahman ho fa amb el foc sagrat.",
  "393": "Un no arriba a ser un brahman per haver nascut brahman, ni pel llinatge o fent austeritats; més aviat, qui està despert a la veritat i al Dharma, qui és pur: aquest és un brahman.",
  "394": "¡Ximple! ¿Per què tens el pèl embullat? ¿Per què la pell de lleopard? Dins teu ets ben ple de defectes, però et guarneixes per fora.",
  "395": "Qui vesteix pobrement, està prim, amb venes visibles per tot el seu cos, meditant en solitud en el bosc: a aquest l'anomeno 'veritable brahman'.",
  "396": "No anomeno 'brahman' a aquell que ha nascut en el ventre de tal llinatge si és un simple arrogant, i menys si hi ha alguna cosa que considera seva. Però aquell que res té i a res està aferrat, a aquest l'anomeno 'veritable brahman'.",
  "397": "El que ha trencat totes les cadenes i mai s'atemoreix, que ha anat més enllà dels lligams: a aquest l'anomeno 'veritable brahman'.",
  "398": "Qui ha tallat la corretja i les regnes, i també la corda i el fre, ha destruït els impediments i està despert: a aquest l'anomeno 'veritable brahman'.",
  "399": "Qui, lliure d'odi, es fa immune als abusos, cops i càstigs, armat amb el poder de la paciència: a aquest l'anomeno 'veritable brahman'.",
  "400": "Qui és lliure d'odi i és responsable, ple de virtut i lliure de la cobdícia, que és tranquil i abasta el seu darrer naixement: a aquest l'anomeno 'veritable brahman'.",
  "401": "Com l'aigua que llisca de les fulles del lotus o el gra de mostassa en la punta d'una agulla, així és el que no s'aferra als plaers sensuals: a aquest l'anomeno 'veritable brahman'.",
  "402": "Qui en aquest món arriba a entendre el cessament de tota insatisfacció, qui ha abandonat les càrregues i s'ha alliberat dels lligams: a aquest l'anomeno 'veritable brahman'.",
  "403": "Qui té un coneixement profund, qui és savi, qui distingeix clarament el camí recte de l'equivocat, qui ha abastat la meta suprema: a aquest l'anomeno 'veritable brahman'.",
  "404": "Lluny dels homes 'de família', lluny dels renunciants, camina sense llar i sense desitjos: a aquest l'anomeno 'veritable brahman'.",
  "405": "Qui ha renunciat a danyar els éssers, tant els que tremolen com els que no, qui no causa la mort ni mata: a aquest l'anomeno 'veritable brahman'.",
  "406": "Entre els hostils, amigable; entre els violents, moderat; desaferrat i generós entre els que s'aferren: a aquest l'anomeno 'veritable brahman'.",
  "407": "Qui no té cobdícia ni odi, presumpció ni menyspreu, com cau el gra de mostassa de la punta d'una agulla: a aquest l'anomeno veritable brahman.",
  "408": "Qui diu paraules enriquidores, veritables i amables, que no ofèn a ningú: a aquest l'anomeno 'veritable brahman'.",
  "409": "Qui en aquest món mai pren el que no li ha estat donat, ja sigui valuós o insignificant, gran o petit, agradable o no: a aquest l'anomeno 'veritable brahman'.",
  "410": "Qui res no desitja, en aquest món ni en l'esdevenir, lliure d'anhels i de lligams: a aquest l'anomeno 'veritable brahman'.",
  "411": "En qui no es troben ni anhels ni aferraments, qui s'ha alliberat dels dubtes gràcies al coneixement final, qui ha penetrat l'Immortal: a aquest l'anomeno 'veritable brahman'.",
  "412": "Qui ha transcendit els dos lligams: tant el bé com el mal, viu satisfet, immaculat i pur; i a aquest l'anomeno 'veritable brahman'.",
  "413": "Qui, com la lluna, immaculada i pura, és net i serè, i qui ha deixat anar el delit per l'existència: a aquest l'anomeno 'veritable brahman'.",
  "414": "Qui ha superat el camí difícil i les cadenes de la falsa il·lusió, qui ha creuat al més enllà, és contemplatiu, sense cobdícia, sense dubtes, calmat i de ment oberta: a aquest l'anomeno 'veritable brahman'.",
  "415": "Qui ha abandonat els desitjos sensuals, com aquell que no té llar i ha renunciat a tot, amb el desig i l'existència exhaurits: a aquest l'anomeno 'veritable brahman'.",
  "416": "Qui ha abandonat la cobdícia, com aquell que no té llar i ha renunciat a tot, amb el desig i l'existència exhaurits: a aquest l'anomeno 'veritable brahman'.",
  "417": "Abandonant tots els lligams humans i anant més enllà dels lligams de les divinitats, completament lliure de totes les cadenes: a aquest l'anomeno 'veritable brahman'.",
  "418": "Abandonant tant el que dóna plaer com el que no, net i lliure de taques, l'heroic conqueridor de l'univers: a aquest l'anomeno 'veritable brahman'.",
  "419": "Qui coneix la destinació dels que moren i el seu renaixement en les diverses formes, desaferrat, sublim, despert: a aquest l'anomeno 'veritable brahman'.",
  "420": "El seu destí és una incògnita, tant pels éssers humans com pels esperits i els déus, ha eliminat les impureses, és l'Arahant: a aquest l'anomeno 'veritable brahman'.",
  "421": "El que s'ha alliberat de tot, del passat, el present i el futur, que res posseeix i viu desaferrat: a aquest l'anomeno 'veritable brahman'.",
  "422": "El noble, l'excels, el conqueridor, gran savi, el que ha conquerit tot, l'impecable, net i despert: a aquest l'anomeno 'veritable brahman'.",
  "423": "Qui coneix les seves existències prèvies i pot veure els estats i l'aflicció d'aquesta, aconsegueix la fi dels renaixements, és el suprem savi amb la visió penetrant, complet en totes les realitzacions: a aquest l'anomeno 'veritable brahman'."
};
